Code.Terraform:
```hcl
# OpenSearch の検索およびインデックススローログを CloudWatch に有効化
resource "aws_opensearch_domain" "<example_resource_name>" {
  domain_name = "<example_resource_name>"

  # 重要: SEARCH_SLOW_LOGS の公開を有効にします
  log_publishing_options {
    log_type                 = "SEARCH_SLOW_LOGS"
    cloudwatch_log_group_arn = "<LOG_GROUP_ARN>"
    enabled                  = true
  }

  # 重要: INDEX_SLOW_LOGS の公開を有効にします
  log_publishing_options {
    log_type                 = "INDEX_SLOW_LOGS"
    cloudwatch_log_group_arn = "<LOG_GROUP_ARN>"
    enabled                  = true
  }
}
```
